mapper.select:
SELECT DISTINCT sur.user_id
FROM sys_user_role sur
WHERE sur.role_id = #{roleId,jdbcType=BIGINT}

mapper.update:
update sys_user
set enabled = #{enabled}
where user_id = #{userId}

update sys_user
set `password`     = #{password},
	pwd_reset_time = #{pwdResetTime}
where user_id = #{userId}
